Create the following Next.js page.tsx wrapper files in C:\Users\User\citedby-ai. Each page is a 'use client' component that imports useAppContext from '@/lib/app-context' and renders the original view component with the correct props.

IMPORTANT: Reference the App.tsx render section to get the exact props each component needs. I'll provide the props for each page.

Create these files using the Write tool:

### 1. app/(app)/dashboard/page.tsx
```typescript
'use client';
import { useAppContext } from '@/lib/app-context';
import Dashboard from '@/views/Dashboard';

export default function DashboardPage() {
  const { goBack, history, handleViewAnalysis, navigateTo } = useAppContext();
  return (
    <Dashboard
      onBack={goBack}
      history={history}
      onView={handleViewAnalysis}
      onNavigate={navigateTo}
    />
  );
}
```

### 2. app/(app)/analyze/page.tsx
```typescript
'use client';
import { useAppContext } from '@/lib/app-context';
import Analyze from '@/views/Analyze';

export default function AnalyzePage() {
  const { handleAnalyze, isAnalyzing } = useAppContext();
  return <Analyze onAnalyze={handleAnalyze} isAnalyzing={isAnalyzing} />;
}
```

### 3. app/(app)/projects/page.tsx
```typescript
'use client';
import { useAppContext } from '@/lib/app-context';
import Projects from '@/views/Projects';

export default function ProjectsPage() {
  const {
    goBack, navigateTo, user, history, handleViewAnalysis,
    monthlyProjectCount, maxProjects, handleDeductCredits,
    handleSaveSolution, analysisData, resultsTab, initialAccountTab,
  } = useAppContext();
  return (
    <Projects
      onBack={goBack}
      onNavigateToAnalysis={() => navigateTo('analyze')}
      user={user}
      history={history}
      onViewAnalysis={handleViewAnalysis}
      projectCount={monthlyProjectCount}
      maxProjects={maxProjects}
      onNavigateToPlan={() => navigateTo('account')}
      onDeductCredits={handleDeductCredits}
      onSaveSolution={handleSaveSolution}
      onNewAnalysis={() => navigateTo('analyze')}
      onNavigateToRecharge={() => navigateTo('recharge')}
      initialUrl={analysisData?.url}
      initialTab={resultsTab}
    />
  );
}
```

### 4. app/(app)/results/page.tsx
```typescript
'use client';
import { useAppContext } from '@/lib/app-context';
import { Results } from '@/views/Results';

export default function ResultsPage() {
  const { analysisData, goBack, user, handleDeductCredits, handleSaveSolution, resultsTab, navigateTo } = useAppContext();
  if (!analysisData) return <div className="p-8 text-slate-400">Aucune analyse selectionnee.</div>;
  return (
    <Results
      data={analysisData}
      onBack={goBack}
      user={user}
      onDeductCredits={handleDeductCredits}
      onSaveSolution={handleSaveSolution}
      initialTab={resultsTab as 'details' | 'archives' | 'overview'}
      onNewAnalysis={() => navigateTo('analyze')}
    />
  );
}
```

